import telebot
from telebot import types
from db import DataBase

db = DataBase('path_to_your_database.db')
bot = telebot.TeleBot('YOUR_BOT_TOKEN')

admins = db.get_admins()

@bot.message_handler(commands=['runblock'])
def runblock(message):
    if message.from_user.id not in admins:
        bot.reply_to(message, 'This command is admin-only.')
        return

    rkb_menu = types.InlineKeyboardMarkup()
    rkb_menu.add(types.InlineKeyboardButton('Draft', callback_data='runblock_draft'))

    bot.send_message(message.chat.id, 'Please select an option:\nDraft', reply_markup=rkb_menu)

@bot.callback_query_handler(func=lambda call: call.data == 'runblock_draft')
def runblock_draft(call):
    if call.message:
        bot.send_message(call.message.chat.id, 'Enter the text for the block.')
        bot.register_next_step_handler(call.message, runblock_apply)

def runblock_apply(message):
    block_text = message.text
    db.run_block(block_text)
    bot.send_message(message.chat.id, 'Block has been drafted successfully.')

@bot.message_handler(commands=['runblock_apply'])
def runblock_apply(message):
    if message.from_user.id not in admins:
        bot.reply_to(message, 'This command is admin-only.')
        return

    blocks = db.get_blocks()
    block_menu = types.ReplyKeyboardMarkup(resize_keyboard=True)
    for block in blocks:
        block_menu.add(block['text'])

    bot.send_message(message.chat.id, 'Choose a block to apply.', reply_markup=block_menu)

bot.polling()

